insert into care_groups (id, temp_min, temp_max, ph_min, ph_max, tank_min, temperament, diet, feeding, lifespan, water_level, schooling_need, schooling_min_group, difficulty, color, tips, fin_nipper, predatory, same_species_aggression_only, breeding_aggression_only, territorial, water_sensitivity) values
  ('guppy', 20, 28, 7, 8, 60, 'peaceful', '플레이크, 브라인쉬림프, 알테미아', '하루 1~2회, 2~3분 내 먹을 양', '3~5년', '상~중층', true, 3, '초급', '#38B6A3', '번식이 매우 빨라 암수 비율 조절이 필요합니다. 새끼를 보호하려면 산란통이나 수초 은신처를 준비하세요.', false, false, false, false, false, 'low'),
  ('betta', 24, 29, 6.5, 7.8, 15, 'aggressive', '베타 전용 펠릿, 냉동 장구벌레', '하루 1회, 소량', '2~3년', '상층', false, 1, '초급', '#E0714F', '수컷끼리는 절대 합사 불가. 화려한 지느러미 어종과도 충돌 위험이 있어 단독 사육을 권장합니다.', false, false, true, false, false, 'low'),
  ('neon-tetra', 21, 26, 5.5, 7.5, 40, 'peaceful', '미세 플레이크, 소형 냉동먹이', '하루 1~2회, 소량씩', '5~8년', '중층', true, 6, '중급', '#38B6A3', '약산성 연수를 선호해 급격한 수질 변화에 민감합니다. 최소 6마리 이상 무리 사육 시 스트레스가 줄어듭니다.', false, false, false, false, false, 'high'),
  ('corydoras', 22, 26, 6.5, 7.5, 60, 'peaceful', '침전성 펠릿, 냉동 장구벌레', '하루 1회, 야간 위주', '5~10년', '하층', true, 4, '초급', '#38B6A3', '바닥재는 모서리가 둥근 모래를 사용해야 수염이 상하지 않습니다. 바닥 청소부 역할을 합니다.', false, false, false, false, false, 'low'),
  ('angelfish', 24, 29, 6.5, 7.4, 100, 'semi-aggressive', '대형 플레이크, 냉동 브라인쉬림프', '하루 1~2회', '8~10년', '중~상층', false, 1, '고급', '#F2A65A', '몸집에 비해 수조가 높아야 합니다(45cm 이상 권장). 소형 어종을 먹이로 인식할 수 있어 합사에 주의하세요.', false, true, false, false, false, 'medium'),
  ('zebra-danio', 18, 24, 6.5, 7.5, 40, 'peaceful', '잡식성 플레이크', '하루 1~2회', '3~5년', '상~중층', true, 6, '초급', '#38B6A3', '매우 활동적이라 뚜껑을 꼭 덮어야 합니다(점프 잘함). 저온에도 강해 초보자에게 적합합니다.', false, false, false, false, false, 'low'),
  ('platy', 20, 26, 7, 8.2, 60, 'peaceful', '잡식성 플레이크, 채소', '하루 1~2회', '3~4년', '중층', true, 3, '초급', '#38B6A3', '번식이 활발한 난태생 어종. 경도가 높은 물을 선호해 구피와 비슷한 환경에서 잘 지냅니다.', false, false, false, false, false, 'low'),
  ('molly', 22, 28, 7.5, 8.5, 100, 'peaceful', '채소성 잡식 (스피룰리나 플레이크)', '하루 1~2회', '3~5년', '중~상층', true, 3, '초급', '#38B6A3', '약염수 환경에서 컨디션이 좋아지는 경우가 많습니다. 채식 비중이 높은 먹이가 필요합니다.', false, false, false, false, false, 'low'),
  ('swordtail', 21, 28, 7, 8.2, 100, 'peaceful', '잡식성', '하루 1~2회', '3~5년', '중~상층', false, 1, '초급', '#38B6A3', '수컷끼리는 서열 다툼이 있을 수 있어 수컷 여러 마리 사육 시 넉넉한 공간이 필요합니다.', false, false, true, false, false, 'low'),
  ('cardinal-tetra', 23, 27, 5.5, 7, 60, 'peaceful', '소형 플레이크, 냉동먹이', '하루 1~2회, 소량', '3~4년', '중층', true, 6, '중급', '#38B6A3', '네온테트라와 흡사하지만 붉은 줄무늬가 몸 전체에 걸쳐 있습니다. 연수/약산성 환경에서 발색이 좋습니다.', false, false, false, false, false, 'high'),
  ('black-skirt-tetra', 20, 26, 6, 7.5, 60, 'peaceful', '잡식성', '하루 1~2회', '3~5년', '중층', true, 5, '초급', '#38B6A3', '지느러미를 무는 습성이 있어 베일테일 어종과는 합사를 피하는 게 좋습니다.', true, false, false, false, false, 'low'),
  ('cherry-barb', 22, 26, 6, 7.5, 60, 'peaceful', '잡식성', '하루 1~2회', '4~6년', '중~하층', true, 5, '초급', '#38B6A3', '온순한 편에 속하는 바브류라 커뮤니티 탱크에 무난합니다.', false, false, false, false, false, 'low'),
  ('tiger-barb', 22, 27, 6, 7.5, 80, 'semi-aggressive', '잡식성', '하루 1~2회', '4~6년', '중층', true, 6, '중급', '#F2A65A', '소수로 키우면 지느러미를 무는 습성이 강해지므로 반드시 6마리 이상 무리로 키워야 합니다.', true, false, false, false, false, 'medium'),
  ('harlequin-rasbora', 23, 27, 5.5, 7, 60, 'peaceful', '소형 플레이크', '하루 1~2회', '5~8년', '중층', true, 6, '초급', '#38B6A3', '무리 지어 다니는 모습이 아름다운 종으로 연수 블랙워터 환경을 선호합니다.', false, false, false, false, false, 'low'),
  ('kuhli-loach', 23, 28, 5.5, 6.5, 60, 'peaceful', '침전성 먹이', '야간 위주 급여', '10년 이상', '하층', true, 3, '중급', '#38B6A3', '장어처럼 가늘고 길쭉하며 낮에는 은신처에 숨어 지내는 야행성입니다.', false, false, false, false, false, 'medium'),
  ('otocinclus', 21, 26, 6.5, 7.5, 40, 'peaceful', '갈조류, 블랜칭한 채소', '매일 소량', '3~5년', '하층', true, 4, '중급', '#38B6A3', '갈조류 청소부로 유명하지만 입식 초기 굶어죽는 경우가 많아 수조에 갈조류가 충분히 생긴 후 입식하는 게 안전합니다.', false, false, false, false, false, 'medium'),
  ('bristlenose-pleco', 23, 27, 6.5, 7.5, 80, 'peaceful', '침전성 플레코 전용 먹이, 채소', '매일', '5~10년', '하층', false, 1, '초급', '#38B6A3', '다른 플레코와 달리 크기가 작아 가정용 수조에 적합한 청소부입니다.', false, false, false, false, false, 'low'),
  ('common-pleco', 22, 28, 6.5, 7.5, 400, 'peaceful', '침전성 채식 위주', '매일', '10~15년', '하층', false, 1, '고급', '#38B6A3', '성어가 되면 45cm 이상 자라 대형 수조가 필수입니다. 소형 수조에서는 절대 키우지 마세요.', false, false, false, false, false, 'medium'),
  ('dwarf-gourami', 22, 28, 6, 7.5, 60, 'semi-aggressive', '잡식성', '하루 1~2회', '4~6년', '상층', false, 1, '초급', '#F2A65A', '수컷끼리는 영역 다툼이 있어 한 수조에 수컷 한 마리만 권장합니다.', false, false, true, false, true, 'low'),
  ('pearl-gourami', 24, 28, 6, 7.5, 100, 'peaceful', '잡식성', '하루 1~2회', '4~8년', '상~중층', false, 1, '중급', '#38B6A3', '구라미 중에서도 성격이 온순한 편이라 커뮤니티 탱크에 잘 어울립니다.', false, false, false, false, false, 'medium'),
  ('honey-gourami', 22, 28, 6, 7.5, 40, 'peaceful', '잡식성', '하루 1~2회', '4년', '상~중층', false, 1, '초급', '#38B6A3', '소형 구라미로 소형 어항에도 적합하며 온순합니다.', false, false, false, false, false, 'low'),
  ('kissing-gourami', 22, 28, 6.5, 8, 300, 'semi-aggressive', '채식성 잡식', '매일', '20년 이상', '중층', false, 1, '고급', '#F2A65A', '이름과 달리 입맞춤은 애정표현이 아닌 힘겨루기입니다. 크게 자라 대형 수조가 필요합니다.', false, false, false, false, false, 'medium'),
  ('discus', 28, 30, 6.4, 7.8, 200, 'peaceful', '디스커스 전용 사료', '하루 2~3회', '10~15년', '중층', true, 5, '고급', '#38B6A3', '높은 수온과 예민한 수질 관리가 필요해 입문자에게는 어려운 종입니다. 잦은 수질 체크가 필수입니다.', false, false, false, false, false, 'high'),
  ('german-blue-ram', 26, 29, 5, 7, 80, 'semi-aggressive', '잡식성', '하루 1~2회', '2~3년', '중~하층', false, 1, '중급', '#F2A65A', '높은 수온을 선호해 다른 저온성 어종과는 합사가 어렵습니다. 짝을 지어 키우면 흥미로운 행동을 볼 수 있습니다.', false, false, false, false, false, 'high'),
  ('kribensis', 24, 27, 6, 7.5, 90, 'semi-aggressive', '잡식성', '하루 1~2회', '3~5년', '하층', false, 1, '중급', '#F2A65A', '산란기에는 영역 방어가 강해지므로 은신처를 충분히 제공해야 합니다.', false, false, false, true, true, 'medium'),
  ('oscar', 22, 27, 6, 8, 250, 'aggressive', '육식성 (펠릿, 냉동새우)', '하루 1회', '10~20년', '중층', false, 1, '고급', '#E0714F', '매우 크게 자라고 지능이 높아 주인을 알아보는 것으로 유명하지만 소형 어종은 먹이로 인식합니다.', false, true, false, false, false, 'medium'),
  ('firemouth-cichlid', 23, 28, 6.5, 8, 120, 'semi-aggressive', '잡식성', '하루 1~2회', '8~10년', '중~하층', false, 1, '중급', '#F2A65A', '위협 시 붉은 아가미를 부풀리는 행동으로 유명합니다. 영역성이 있어 넓은 수조가 필요합니다.', false, false, false, false, true, 'medium'),
  ('convict-cichlid', 22, 27, 6, 8, 120, 'aggressive', '잡식성', '하루 1~2회', '8~10년', '중~하층', false, 1, '중급', '#E0714F', '번식력이 매우 강하고 새끼를 지킬 때 공격성이 극도로 높아집니다.', false, false, false, true, false, 'medium'),
  ('rainbow-shark', 22, 27, 6.5, 7.5, 150, 'aggressive', '잡식성', '하루 1회', '6~8년', '하층', false, 1, '중급', '#E0714F', '영역성이 강해 자신과 비슷한 체형의 어종을 공격하는 경우가 많습니다. 한 수조에 한 마리만 권장합니다.', false, false, true, false, true, 'medium'),
  ('bala-shark', 24, 28, 6, 7.5, 500, 'peaceful', '잡식성', '하루 1~2회', '10년 이상', '중~상층', true, 4, '고급', '#38B6A3', '성어가 되면 매우 크게 자라고 무리 생활이 필요해 대형 수조가 아니면 키우기 어렵습니다.', false, true, false, false, false, 'medium'),
  ('rosy-barb', 18, 25, 6, 8, 80, 'semi-aggressive', '잡식성', '하루 1~2회', '4~6년', '중층', true, 5, '초급', '#F2A65A', '평소엔 온순하지만 무리가 5마리 미만으로 부족하면 지느러미를 무는 습성이 나타납니다. 베타나 엔젤피시처럼 지느러미가 길고 느린 어종과는 합사를 피하세요.', true, false, false, false, false, 'low'),
  ('endlers-livebearer', 22, 28, 7, 8.5, 30, 'peaceful', '잡식성', '하루 1~2회', '2~3년', '상~중층', true, 3, '초급', '#38B6A3', '구피와 유사하지만 크기가 더 작고 색이 화려합니다. 구피와 교잡이 가능해 순종 유지를 원하면 분리 사육해야 합니다.', false, false, false, false, false, 'low'),
  ('celestial-pearl-danio', 20, 25, 6, 7.5, 40, 'peaceful', '소형 플레이크, 미세 먹이', '하루 2회 소량', '3~5년', '중~하층', true, 6, '중급', '#38B6A3', '몸집이 매우 작아 소형 수조에 적합하지만 입이 작아 먹이 크기를 신경 써야 합니다.', false, false, false, false, false, 'medium'),
  ('white-cloud-mountain-minnow', 16, 24, 6, 8, 40, 'peaceful', '잡식성', '하루 1~2회', '3~5년', '중~상층', true, 6, '초급', '#38B6A3', '저온에 강해 히터 없는 냉수 수조에서도 사육이 가능합니다. 단독 또는 소수로 키우면 오히려 다른 온순한 어종(구피, 할리퀸라스보라 등)을 쫓아다니며 지느러미를 무는 경우가 보고되어, 충분한 무리로 키우는 게 안전합니다.', true, false, false, false, false, 'low'),
  ('glowlight-tetra', 23, 27, 6, 7, 45, 'peaceful', '소형 플레이크', '하루 1~2회', '3~5년', '중층', true, 6, '초급', '#38B6A3', '은은하게 빛나는 주황색 줄무늬가 특징이며 성격이 온순합니다.', false, false, false, false, false, 'low'),
  ('ember-tetra', 23, 28, 5.5, 7, 40, 'peaceful', '초소형 플레이크', '하루 2회 소량', '2~3년', '중층', true, 8, '초급', '#38B6A3', '매우 작은 몸집이라 소형 수조에도 무리 지어 키우기 좋습니다.', false, false, false, false, false, 'low'),
  ('rummynose-tetra', 24, 28, 5.5, 7, 60, 'peaceful', '소형 플레이크', '하루 1~2회', '5~6년', '중층', true, 8, '중급', '#38B6A3', '코 끝의 붉은색이 진하게 나타나는 것은 수질이 안정적이라는 신호로 여겨집니다.', false, false, false, false, false, 'high'),
  ('congo-tetra', 23, 27, 6, 7, 100, 'peaceful', '잡식성', '하루 1~2회', '3~5년', '중층', true, 6, '중급', '#38B6A3', '수컷의 무지갯빛 비늘과 긴 지느러미가 특징이며 넓은 유영 공간이 필요합니다.', false, false, false, false, false, 'medium'),
  ('silver-dollar', 23, 27, 6, 7, 300, 'peaceful', '채식 위주 잡식성', '하루 1~2회', '10년 이상', '중층', true, 5, '중급', '#38B6A3', '수초를 매우 잘 뜯어먹어 살아있는 수초와 함께 키우기 어렵습니다.', false, false, false, false, false, 'medium'),
  ('clown-loach', 25, 30, 6, 7.5, 400, 'peaceful', '잡식성', '하루 1회', '15~20년', '중~하층', true, 5, '고급', '#38B6A3', '매우 크게 자라고 장수하며 무리 생활이 필수라 대형 수조와 장기 계획이 필요합니다.', false, false, false, false, false, 'medium'),
  ('yoyo-loach', 20, 27, 6.5, 7.5, 150, 'peaceful', '잡식성', '하루 1회', '8~10년', '하층', true, 5, '중급', '#38B6A3', '무늬가 성장하며 변하는 것이 특징이며 달팽이 제거에 효과적입니다.', false, false, false, false, false, 'medium'),
  ('flying-fox', 22, 26, 6, 7.5, 100, 'semi-aggressive', '잡식성 (갈조류 포함)', '하루 1회', '8~10년', '하층', false, 1, '중급', '#F2A65A', '레인보우샤크와 혼동되지만 상대적으로 온순하나 같은 종끼리는 다툼이 있습니다.', false, false, false, false, false, 'medium'),
  ('siamese-algae-eater', 24, 27, 6.5, 7.5, 100, 'peaceful', '갈조류, 채소', '매일', '5~10년', '하층', true, 3, '중급', '#38B6A3', '검은 수염말(black beard algae)까지 먹는 몇 안 되는 어종으로 조류 관리에 유용합니다.', false, false, false, false, false, 'medium'),
  ('bolivian-ram', 23, 27, 6.5, 7.5, 80, 'peaceful', '잡식성', '하루 1~2회', '3~4년', '중~하층', false, 1, '중급', '#38B6A3', '저먼블루람보다 온도 적응력이 넓어 커뮤니티 탱크에 합사하기 수월합니다.', false, false, false, false, false, 'medium'),
  ('jack-dempsey', 24, 28, 6.5, 7.5, 250, 'aggressive', '육식성 잡식', '하루 1회', '10~15년', '중~하층', false, 1, '고급', '#E0714F', '성체가 되면 공격성이 매우 강해져 단독 사육이나 비슷한 크기의 시클리드와만 합사해야 합니다.', false, true, false, false, false, 'medium'),
