  ('puffer-brackish', 24, 28, 7.8, 9, 100, 'aggressive', '육식성 (달팽이, 갑각류)', '매일', '5~10년', '중~하층', false, 1, '고급', '#E0714F', '어릴 때는 담수에서도 지낼 수 있지만, 성장하면서 점차 기수~해수 수준의 염분이 필요해집니다. 순수 담수만으로는 장기적으로 건강을 유지하기 어렵습니다.', false, true, false, false, false, 'medium'),
  ('puffer-giant-freshwater', 24, 26, 6.5, 7.5, 500, 'aggressive', '육식성 (달팽이, 갑각류, 생먹이)', '하루 1회', '10년 이상', '중~하층', false, 1, '고급', '#E0714F', '완전 담수에서 사육 가능한 대형 퍼퍼로 사람을 알아볼 정도로 영리하지만 매우 공격적이라 반드시 단독 사육해야 합니다.', false, true, false, false, false, 'medium'),
  ('killifish-clown', 20, 26, 5, 7, 30, 'peaceful', '소형 육식성 (모기유충 등)', '소량씩 자주', '2~3년', '상층', true, 6, '중급', '#38B6A3', '수면 근처에 떠서 지내는 표층 어종으로, 뚜껑이 없는 수조에서는 점프에 주의해야 합니다.', false, false, false, false, false, 'medium'),
  ('killifish-annual', 22, 26, 6, 7.5, 40, 'semi-aggressive', '육식성', '매일', '1년 내외 (연간어)', '상~중층', false, 1, '고급', '#E0714F', '우기와 건기가 반복되는 서식지 특성상, 알이 마른 진흙 속에서 수개월간 휴면(다이어폴즈)했다가 부화하는 독특한 생활사를 가집니다. 이탄(피트모스) 산란상이 필요해 일반 어종과는 완전히 다른 번식 관리가 필요합니다.', false, false, false, false, false, 'medium'),
  ('rainbowfish-melanotaenia', 22, 30, 6.5, 8.5, 100, 'peaceful', '잡식성', '하루 1~2회', '5~8년', '중~상층', true, 6, '중급', '#38B6A3', '활발하게 헤엄치는 어종이라 폭이 넓은 수조가 필요하며, 무리 지어 키울 때 수컷의 발색이 더 화려해집니다.', false, false, false, false, false, 'medium'),
  ('rainbowfish-nano-blueeye', 22, 28, 5.5, 7.5, 40, 'peaceful', '소형 잡식성', '소량씩 자주', '2~3년', '중~상층', true, 8, '중급', '#38B6A3', '일반 레인보우피시보다 훨씬 작은 나노 어종으로, 소형 수조에서도 무리 지어 키울 수 있습니다.', false, false, false, false, false, 'medium'),
  ('rainbowfish-madagascar', 23, 28, 5.5, 7.5, 100, 'peaceful', '육식성 위주', '하루 1~2회', '5년 내외', '중~상층', true, 6, '중급', '#F2A65A', '다른 레인보우피시와 달리 육식 성향이 강해 단백질 비율이 높은 먹이가 필요합니다.', false, false, false, false, false, 'medium'),
  ('black-shark', 22, 28, 6.5, 8, 500, 'aggressive', '잡식성 (갈조류 포함)', '하루 1회', '10년 이상', '중~하층', false, 1, '고급', '#E0714F', '성어가 되면 60cm 이상 자라고 동종 및 비슷한 체형의 어종에게 매우 공격적이라 반드시 단독 사육해야 합니다.', false, false, false, false, false, 'medium'),
  ('brackish-shark-catfish', 25, 27, 6.8, 8, 300, 'semi-aggressive', '육식성 잡식', '하루 1회', '10~15년', '중층', true, 3, '고급', '#F2A65A', '이름과 겉모습은 상어를 닮았지만 실제로는 메기류입니다. 어릴 때는 담수에서 지낼 수 있지만 성장하면서 기수(brackish) 수준의 염분이 필요해지므로 장기적으로는 소금 첨가가 필요합니다.', false, false, false, false, false, 'medium'),
  ('hatchetfish-silver', 23, 27, 6, 7, 60, 'peaceful', '표층 소형 먹이 (날파리 등 선호)', '소량씩 자주', '3~5년', '상층', true, 6, '중급', '#38B6A3', '수면 위로 뛰어올라 날아다니는 듯한 특이한 습성이 있어 반드시 뚜껑이 있는 수조가 필요합니다. 표층에서만 활동하므로 폭이 넓은 수조가 유리합니다.', false, false, false, false, false, 'medium'),
  ('black-ghost-knifefish', 24, 28, 6.5, 7.5, 300, 'semi-aggressive', '육식성 (야간 위주)', '야간 위주 급여', '10~15년', '중~하층', false, 1, '고급', '#F2A65A', '약한 전기를 발생시켜 주변을 감지하는 야행성 어종입니다. 동종끼리 매우 공격적이라 한 수조에 한 마리만 키우는 것이 안전합니다.', false, true, true, false, false, 'medium'),
  ('pencil-fish', 23, 27, 5.5, 7, 60, 'peaceful', '소형 잡식성', '소량씩 자주', '3~5년', '중층', true, 6, '중급', '#38B6A3', '네온테트라와 비슷한 크기의 온순한 어종으로, 약산성 연수 환경과 무리 사육 시 컨디션이 좋습니다.', false, false, false, false, false, 'medium'),
  ('african-red-eye-tetra', 23, 27, 6, 7.5, 100, 'peaceful', '잡식성', '하루 1~2회', '5년 내외', '중~상층', true, 6, '중급', '#38B6A3', '콩고테트라와 마찬가지로 아프리카산 대형 테트라로, 무리 지어 키울 때 헤엄치는 모습이 화려합니다.', false, false, false, false, false, 'medium'),
  ('headstander-fish', 24, 28, 6, 7.5, 100, 'peaceful', '잡식성', '하루 1~2회', '5~8년', '중~하층', true, 5, '중급', '#38B6A3', '머리를 아래로 향한 채 45도 각도로 떠다니는 독특한 자세가 특징인 어종입니다.', false, false, false, false, false, 'medium'),
  ('prochilodus', 24, 28, 6, 7.5, 300, 'peaceful', '잡식성 (조류, 유기물 포함)', '매일', '10년 내외', '중~하층', true, 5, '중급', '#38B6A3', '성어가 되면 30cm 가까이 자라는 대형 어종으로 무리 지어 키우려면 넓은 수조가 필요합니다.', false, false, false, false, false, 'medium'),
  ('piranha', 24, 28, 6, 7.5, 300, 'aggressive', '육식성 (육류, 생선)', '하루 1회', '10년 이상', '중층', true, 5, '고급', '#E0714F', '다른 어종과의 합사는 사실상 불가능하며 반드시 피라냐끼리만 무리 사육해야 합니다. 국가/지역에 따라 소유·수입이 법적으로 제한될 수 있으니 사전에 확인이 필요합니다.', false, true, false, false, false, 'medium'),
  ('pacu', 23, 28, 6, 7.5, 1000, 'peaceful', '채식 위주 잡식성', '매일', '15~20년 이상', '중층', false, 1, '고급', '#F2A65A', '피라냐와 혼동되지만 실제로는 온순한 초식성 대형어입니다. 성어가 되면 60~90cm까지 자라 가정용 수조로는 감당하기 어려운 경우가 대부분이라 신중한 사전 조사가 필요합니다.', false, false, false, false, false, 'medium'),
  ('serpae-tetra', 23, 27, 5.5, 7.5, 80, 'semi-aggressive', '잡식성', '하루 1~2회', '5~7년', '중층', true, 8, '중급', '#F2A65A', '다른 테트라에 비해 지느러미를 무는 습성이 강한 편이라, 긴 지느러미를 가진 어종과는 합사를 피하는 게 좋습니다. 충분히 큰 무리로 키우면 공격성이 분산됩니다.', true, false, false, false, false, 'low'),
  ('bleeding-heart-tetra', 23, 27, 6, 7.5, 100, 'peaceful', '잡식성', '하루 1~2회', '5년 내외', '중층', true, 6, '중급', '#38B6A3', '가슴 부위의 붉은 반점이 특징이며, 혼자 있으면 다소 신경질적이 되므로 충분한 무리로 키우는 게 좋습니다.', true, false, false, false, false, 'medium'),
  ('diamond-tetra', 23, 27, 6, 7.5, 100, 'peaceful', '잡식성', '하루 1~2회', '5년 내외', '중층', true, 6, '중급', '#38B6A3', '몸 전체에 다이아몬드처럼 반짝이는 비늘이 특징인 온순한 테트라입니다.', false, false, false, false, false, 'medium'),
  ('buenos-aires-tetra', 18, 26, 6, 8, 120, 'semi-aggressive', '잡식성 (수초도 먹음)', '하루 1~2회', '5년 내외', '중층', true, 6, '초급', '#F2A65A', '저온에도 강해 사육이 쉽지만 수초를 뜯어먹는 습성이 있어 유코 수조에는 적합하지 않습니다.', true, false, false, false, false, 'low'),
  ('emperor-tetra', 23, 28, 5.5, 7.5, 80, 'peaceful', '잡식성', '하루 1~2회', '5년 내외', '중층', true, 6, '중급', '#38B6A3', '테트라 중에서도 기품 있는 외모로 인기가 많으며 비교적 사육이 수월한 편입니다.', false, false, false, false, false, 'medium'),
  ('penguin-tetra', 23, 27, 6, 7.5, 80, 'peaceful', '잡식성', '하루 1~2회', '5년 내외', '중~상층', true, 6, '초급', '#38B6A3', '비스듬히 위를 향해 헤엄치는 독특한 자세가 특징인 온순한 테트라입니다.', false, false, false, false, false, 'low'),
  ('blind-cave-tetra', 20, 26, 6, 8, 80, 'peaceful', '잡식성', '하루 1~2회', '5~10년', '중~하층', true, 6, '초급', '#F2A65A', '동굴에 적응하며 눈이 퇴화된 독특한 어종으로 시각 대신 측선을 이용해 주변을 감지합니다. 어두운 조명에서도 잘 적응합니다.', false, false, false, false, false, 'low'),
  ('apistogramma', 24, 28, 5.5, 7, 60, 'semi-aggressive', '잡식성', '하루 1~2회', '2~4년', '하층', false, 1, '중급', '#F2A65A', '수컷 1마리에 암컷 여러 마리로 구성된 하렘 형태로 키우면 공격성이 분산됩니다. 은신처와 고운 모래 바닥이 필요합니다.', false, false, true, false, false, 'medium'),
  ('polypterus', 24, 28, 6.5, 7.5, 300, 'aggressive', '육식성', '하루 1회, 야간 위주', '15년 이상', '하층', false, 1, '고급', '#E0714F', '고대어종으로 공기 호흡이 가능해 수면 위로 자주 올라옵니다. 탈출의 명수라 뚜껑이 반드시 필요하고, 입에 들어가는 크기의 물고기는 먹이로 인식합니다.', false, true, false, false, false, 'medium'),
  ('spiny-eel', 24, 28, 6.5, 7.5, 150, 'peaceful', '육식성 (살아있는 먹이 선호)', '야간 위주 급여', '8~10년', '하층', false, 1, '중급', '#F2A65A', '몸이 가늘고 길어 좁은 틈새로 파고드는 습성이 있어 여과기 흡입구를 반드시 막아야 하며, 모래 바닥에 파고들기를 좋아합니다.', false, false, false, false, false, 'medium'),
  ('halfbeak', 24, 28, 7, 8, 60, 'semi-aggressive', '육식성 (모기유충 등)', '하루 1~2회', '1~2년', '상층', true, 4, '중급', '#F2A65A', '수컷끼리는 격렬하게 싸우는 습성이 있어 한 수조에 수컷 한 마리만 권장합니다. 표층 서식 어종으로 점프에 주의해야 합니다.', false, false, true, false, false, 'medium'),
  ('gold-barb', 18, 25, 6, 8, 100, 'peaceful', '잡식성', '하루 1~2회', '5~6년', '중층', true, 5, '초급', '#38B6A3', '저온에도 강해 사육이 쉬운 편이며, 무리 지어 키우면 서로간의 다툼이 줄어듭니다.', false, false, false, false, false, 'low'),
  ('denison-barb', 15, 25, 6.5, 7.8, 300, 'peaceful', '잡식성', '하루 1~2회', '7~8년', '중층', true, 6, '고급', '#F2A65A', '빠르게 흐르는 하천 출신이라 강한 수류와 높은 용존산소가 필요합니다. 남획으로 개체수가 줄어든 종이라 양식산인지 확인 후 구매하는 것이 좋습니다.', false, false, false, false, false, 'medium'),
  ('weather-loach', 15, 25, 6, 8, 150, 'peaceful', '잡식성', '하루 1회', '10년 이상', '하층', true, 3, '초급', '#38B6A3', '저온에 매우 강해 히터 없이도 사육 가능하며, 기압 변화를 감지해 날씨가 흐려지면 활발히 움직이는 것으로 유명합니다.', false, false, false, false, false, 'low'),
  ('zebra-loach', 24, 28, 6.5, 7.5, 150, 'peaceful', '잡식성', '하루 1회', '8~10년', '하층', true, 6, '중급', '#38B6A3', '다른 보티아속 로치보다 온순한 편이라 커뮤니티 탱크에 비교적 무난하게 어울립니다.', false, false, false, false, false, 'low'),
  ('giant-danio', 22, 26, 6, 8, 150, 'peaceful', '잡식성', '하루 1~2회', '5~7년', '중~상층', true, 6, '초급', '#38B6A3', '일반 제브라다니오보다 훨씬 크고 활동적이라 폭이 넓은 수조가 필요합니다.', false, false, false, false, false, 'low'),
  ('chili-rasbora', 23, 27, 4, 6.5, 40, 'peaceful', '초소형 먹이', '소량씩 자주', '2~3년', '중층', true, 10, '중급', '#E0714F', '매우 작은 나노 어종으로 연수·약산성 블랙워터 환경에서 발색이 좋습니다. 입이 작아 초소형 먹이가 필요합니다.', false, false, false, false, false, 'medium'),
  ('scissortail-rasbora', 22, 27, 6, 7.5, 100, 'peaceful', '잡식성', '하루 1~2회', '5~8년', '중~상층', true, 6, '초급', '#38B6A3', '가위처럼 벌어지는 꼬리지느러미 움직임이 특징이며, 다른 라스보라보다 크게 자라 넓은 수조가 유리합니다.', false, false, false, false, false, 'low'),
  ('orange-chromide', 24, 28, 7, 8.5, 150, 'semi-aggressive', '잡식성', '하루 1~2회', '5~8년', '중~하층', false, 1, '중급', '#F2A65A', '인도/스리랑카산 시클리드로 기수(brackish) 환경에서도 잘 적응하며, 약간의 소금을 첨가하면 컨디션이 좋아지는 경우가 많습니다.', false, false, false, false, false, 'medium'),
  ('fire-eel', 24, 28, 6.5, 7.5, 600, 'semi-aggressive', '육식성 (살아있는 먹이 선호)', '야간 위주 급여', '8~10년', '하층', false, 1, '고급', '#E0714F', '일반 스파이니일보다 훨씬 크게 자라는 대형종(1m 내외)으로 성장을 고려한 대형 수조가 필요합니다.', false, true, false, false, false, 'medium'),
  ('tinfoil-barb', 22, 28, 6.5, 7.5, 470, 'semi-aggressive', '초식성 위주 잡식', '하루 1~2회', '10년 내외', '중층', true, 5, '중급', '#F2A65A', '30cm 가까이 자라는 대형 바브로 큰 수조가 필요하며, 수초를 뜯어먹고 입에 들어가는 작은 물고기를 먹이로 인식할 수 있습니다.', false, true, false, false, false, 'low'),
  ('iridescent-shark', 22, 28, 6.5, 7.5, 1000, 'peaceful', '잡식성', '하루 1회', '15~20년', '중~하층', true, 5, '고급', '#E0714F', '판매 시엔 작지만 야생에서 1m 이상, 가정 수조에서도 60cm 이상 자라는 초대형 메기입니다. 어릴 때 예뻐서 충동구매하는 경우가 많지만 대부분의 가정에서 감당하기 어려운 크기까지 자랍니다.', false, false, false, false, false, 'low'),
  ('chinese-algae-eater', 22, 28, 6.5, 7.5, 120, 'aggressive', '갈조류, 잡식성', '매일', '10년 내외', '하층', false, 1, '중급', '#E0714F', '어릴 때는 온순한 갈조류 청소부지만, 성장하면서 다른 물고기의 옆구리를 빨아 점액을 뜯어먹는 공격적인 습성이 생기는 것으로 악명 높습니다. 오토싱클루스와 혼동되지만 다 크면 전혀 다른 어종입니다.', false, false, true, false, true, 'low');
