insert into species_pair_overrides (species_a, species_b, result, reason, source) values
  ('betta', 'corydoras', 'caution', '베타는 하층에서 조용히 지내는 코리도라스는 대체로 무시하는 편이라 실제로 널리 쓰이는 조합입니다. 다만 베타 개체 성격 차이가 커서 완전히 안전하다고 보긴 어렵습니다.', '커뮤니티 관찰'),
  ('red-belly-piranha-sp', 'silver-dollar', 'caution', '피라냐와 실버달러는 남미에서 실제로 서식지를 공유하는 조합으로, 실버달러의 빠른 유영 속도 덕분에 충분히 큰 수조에서는 종종 함께 사육됩니다. 그래도 위험이 완전히 없는 건 아니라 대형 수조와 충분한 무리가 전제됩니다.', '도감/커뮤니티');
